 1	import * as React from 'react';
 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { Link } from 'react-router-dom-v5-compat';
 4	import { Status } from '../../types/Health';
 5	import { Paths } from '../../config';
 6	import { ActiveFilter, DEFAULT_LABEL_OPERATION } from '../../types/Filters';
 7	import { healthFilter } from '../../components/Filters/CommonFilters';
 8	import { FilterSelected } from '../../components/Filters/StatefulFilters';
 9	import { KialiAppState } from '../../store/Store';
10	import { connect } from 'react-redux';
11	import { isParentKiosk, kioskGraphAction } from '../../components/Kiosk/KioskActions';
12	import { durationSelector, refreshIntervalSelector } from '../../store/Selectors';
13	import { DurationInSeconds, IntervalInMilliseconds } from '../../types/Common';
14	import { healthIndicatorStyle } from 'styles/HealthStyle';
15	import { createIcon } from 'config/KialiIcon';
16	
17	type ReduxProps = {
18	  duration: DurationInSeconds;
19	  kiosk: string;
20	  refreshInterval: IntervalInMilliseconds;
21	};
22	
23	type Props = ReduxProps & {
24	  id: string;
25	  items: string[];
26	  namespace: string;
27	  status: Status;
28	  targetPage: Paths;
29	};
30	
31	const OverviewStatusComponent: React.FC<Props> = (props: Props) => {
32	  const setFilters = (): void => {
33	    const filters: ActiveFilter[] = [
34	      {
35	        category: healthFilter.category,
36	        value: props.status.name
37	      }
38	    ];
39	
40	    FilterSelected.setSelected({ filters: filters, op: DEFAULT_LABEL_OPERATION });
41	  };
42	
43	  const linkAction = (): void => {
44	    // Kiosk actions are used when the kiosk specifies a parent,
45	    // otherwise the kiosk=true will keep the links inside Kiali
46	    if (isParentKiosk(props.kiosk)) {
47	      kioskGraphAction(props.namespace, props.status.name, props.duration, props.refreshInterval, props.targetPage);
48	    } else {
49	      setFilters();
50	    }
51	  };
52	
53	  const length = props.items.length;
54	  let items = props.items;
55	
56	  if (items.length > 6) {
57	    items = items.slice(0, 5);
58	    items.push(`and ${length - items.length} more...`);
59	  }
60	
61	  const tooltipContent = (
62	    <div>
63	      <strong>{props.status.name}</strong>
64	
65	      {items.map((app, idx) => {
66	        return (
67	          <div data-test={`${props.id}-${app}`} key={`${props.id}-${idx}`}>
68	            <span style={{ marginRight: '0.5rem' }}>{createIcon(props.status)}</span> {app}
69	          </div>
70	        );
71	      })}
72	    </div>
73	  );
74	
75	  return (
76	    <Tooltip
77	      aria-label={'Overview status'}
78	      position={TooltipPosition.auto}
79	      content={tooltipContent}
80	      className={healthIndicatorStyle}
81	    >
82	      <div style={{ display: 'inline-block', marginRight: '0.375rem' }}>
83	        <Link to={`/${props.targetPage}?namespaces=${props.namespace}`} onClick={() => linkAction()}>
84	          {createIcon(props.status)}
85	          {` ${length}`}
86	        </Link>
87	      </div>
88	    </Tooltip>
89	  );
90	};
91	
92	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
93	  duration: durationSelector(state),
94	  kiosk: state.globalState.kiosk,
95	  refreshInterval: refreshIntervalSelector(state)
96	});
97	
98	export const OverviewStatus = connect(mapStateToProps)(OverviewStatusComponent);

